CREATE TABLE "BranchOpening" ("id" TEXT NOT NULL PRIMARY KEY,"branchId" TEXT NOT NULL,"title" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'PLANNING',"plannedStartDate" DATETIME,"plannedOpeningDate" DATETIME NOT NULL,"actualOpeningDate" DATETIME,"progressPercentage" INTEGER NOT NULL DEFAULT 0,"projectManager" TEXT,"generalNotes" TEXT,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL,"archivedAt" DATETIME,CONSTRAINT "BranchOpening_branchId_fkey" FOREIGN KEY("branchId") REFERENCES "Branch"("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE INDEX "BranchOpening_branchId_archivedAt_idx" ON "BranchOpening"("branchId","archivedAt");CREATE INDEX "BranchOpening_status_plannedOpeningDate_idx" ON "BranchOpening"("status","plannedOpeningDate");CREATE UNIQUE INDEX "BranchOpening_one_active_per_branch" ON "BranchOpening"("branchId") WHERE "archivedAt" IS NULL AND "status" NOT IN ('COMPLETED','CANCELLED');
CREATE TABLE "OpeningStage" ("id" TEXT NOT NULL PRIMARY KEY,"openingId" TEXT NOT NULL,"stageType" TEXT NOT NULL,"title" TEXT NOT NULL,"description" TEXT,"status" TEXT NOT NULL DEFAULT 'NOT_STARTED',"assignedTo" TEXT,"plannedStartDate" DATETIME,"dueDate" DATETIME,"completedAt" DATETIME,"progressPercentage" INTEGER NOT NULL DEFAULT 0,"orderIndex" INTEGER NOT NULL,"delayReason" TEXT,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL,CONSTRAINT "OpeningStage_openingId_fkey" FOREIGN KEY("openingId") REFERENCES "BranchOpening"("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE INDEX "OpeningStage_openingId_orderIndex_idx" ON "OpeningStage"("openingId","orderIndex");CREATE INDEX "OpeningStage_status_dueDate_idx" ON "OpeningStage"("status","dueDate");
CREATE TABLE "OpeningTask" ("id" TEXT NOT NULL PRIMARY KEY,"openingStageId" TEXT NOT NULL,"title" TEXT NOT NULL,"description" TEXT,"assignedTo" TEXT,"priority" TEXT NOT NULL DEFAULT 'NORMAL',"status" TEXT NOT NULL DEFAULT 'OPEN',"dueDate" DATETIME,"completedAt" DATETIME,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL,CONSTRAINT "OpeningTask_openingStageId_fkey" FOREIGN KEY("openingStageId") REFERENCES "OpeningStage"("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE INDEX "OpeningTask_openingStageId_dueDate_idx" ON "OpeningTask"("openingStageId","dueDate");CREATE INDEX "OpeningTask_status_dueDate_idx" ON "OpeningTask"("status","dueDate");
ALTER TABLE "Document" ADD COLUMN "openingId" TEXT REFERENCES "BranchOpening"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
CREATE INDEX "Document_openingId_idx" ON "Document"("openingId");
